## Code Example

```javascript
// Example Cypress test
describe('Onboarding wizard', () => {
  beforeEach(() => {
    cy.clearLocalStorage();
    cy.viewport(1024, 768);
  });

  it('persists progress and uses deterministic API', () => {
    cy.intercept('POST', '/api/create-account', { id: 'user-123', status: 'ok' }).as('create');
    cy.visit('/onboarding');
    cy.get('[data-testid="step1-name"]').type('Alex');
    cy.get('[data-testid="step1-name"]').should('have.value', 'Alex');
    cy.get('[data-testid="next"]').click();
    cy.get('[data-testid="step2-email"]').type('alex@example.com');
    cy.get('[data-testid="submit"]').click();
    cy.wait('@create');
    cy.get('[data-testid="final-title"]').should('contain', 'Welcome, Alex');
  });
});
```

