test.describe('Flag-gated checkout', () => {
  test('flag ON renders new UI and processes purchase', async ({ page }) => {
    // mock flag service to ON for tenant A
    await page.route('**/flags/**', route =>
      route.fulfill({ status: 200, body: JSON.stringify({ flag: 'on' }) })
