## Code Example

```javascript
// Cypress skeleton for tenant isolation
describe('Tenant isolation', () => {
  beforeEach(() => {
    seedTenants(['A','B']);
  });
  it('creates user in A and enforces isolation', () => {
    cy.visit('/login');
    cy.login('adminA','A');
    cy.visit('/admin/users');
    cy.get('[data-cy=create-user]').click();
    cy.get('[data-cy=username]').type('newuser');
    cy.get('[data-cy=save]').click();
    cy.contains('newuser').should('exist');
    cy.request({method:'GET', url:'/api/users?tenant=A'}).then(resp => {
      expect(resp.body.some(u => u.username==='newuser')).to.be.true;
    });
    cy.request({method:'GET', url:'/api/users?tenant=B'}).then(resp => {
      expect(resp.body.some(u => u.username==='newuser')).to.be.false;
    });
  });
});
```

