questions.answer:
Use Playwright with two parallel browser contexts simulating editors in US and EU regions. For flag gating, integrate with LaunchDarkly API via SDK client to toggle flags programmatically per test, or use test-specific user targeting rules.

**Complete Playwright Test Implementation:**

```typescript
import { test, expect, chromium } from '@playwright/test';
import WebSocket from 'ws';

const LAUNCHDARKLY_SDK_KEY = process.env.LD_SDK_KEY;
const FEATURE_FLAG_KEY = 'regional-post-editor-eu';

interface EditorMessage {
  type: 'UPDATE' | 'ACK' | 'SYNC';
  postId: string;
  content: string;
  version: number;
  timestamp: number;
  region: 'US' | 'EU';
}

class LaunchDarklyClient {
  private client: any;

  async initialize() {
    const ld = await import('launchdarkly-node-server-sdk');
    this.client = ld.init(LAUNCHDARKLY_SDK_KEY);
    await this.client.waitForInitialization();
  }

  async toggleFlag(enabled: boolean, targetUsers: string[]) {
    const flags = await this.client.getFlagRules();
    for (const userKey of targetUsers) {
      await this.client.upsert({ key: userKey }, {
        [FEATURE_FLAG_KEY]: enabled
      });
    }
  }

  async close() {
    await this.client.close();
  }
}

test.describe('E2E: Real-time Collaborative Post Editor', () => {
  let ldClient: LaunchDarklyClient;

  test.beforeAll(async () => {
    ldClient = new LaunchDarklyClient();
    await ldClient.initialize();
  });

  test.afterAll(async () => {
    await ldClient.close();
  });

  test('US region: should allow editing with optimistic UI and WebSocket propagation', async () => {
    const browser = await chromium.launch();
    const context = await browser.newContext({
      locale: 'en-US',
      timezoneId: 'America/New_York',
    });
    const page = await context.newPage();

    const wsEndpoint = await loginAndGetWebSocket(page, 'us-editor');
    const ws = new WebSocket(wsEndpoint);

    const messages: EditorMessage[] = [];
    ws.on('message', (data) => {
      const msg = JSON.parse(data.toString()) as EditorMessage;
      messages.push(msg);
    });

    await page.goto('/app/editor/post-123');
    await page.waitForSelector('[data-testid="editor-content"]');

    // Optimistic UI: immediate local update before server ACK
    const localVersion = await page.evaluate(() => {
      return (window as any).__editorState?.version || 0;
    });

    await page.click('[data-testid="editor-content"]');
    await page.keyboard.type('Hello World');

    // Verify optimistic UI - local state updated immediately
    const optimisticContent = await page.textContent('[data-testid="editor-content"]');
    expect(optimisticContent).toBe('Hello World');

    // Wait for WebSocket ACK
    await page.waitForFunction(() => {
      return (window as any).__editorState?.synced;
    }, { timeout: 5000 });

    // Verify WebSocket message sent
    const sentFrame = messages.filter(m => m.type === 'UPDATE');
    expect(sentFrame).toHaveLength(1);
    expect(sentFrame[0].content).toBe('Hello World');
    expect(sentFrame[0].region).toBe('US');

    await ws.close();
    await browser.close();
  });

  test('EU region: should gate content behind feature flag', async () => {
    const browser = await chromium.launch();
    const context = await browser.newContext({
      locale: 'de-DE',
      timezoneId: 'Europe/Berlin',
    });
    const page = await context.newPage();

    // Enable flag for EU user before navigation
    await ldClient.toggleFlag(true, ['eu-editor-user']);

    await page.goto('/app/editor/post-123', {
      headers: { 'X-User-Key': 'eu-editor-user' }
    });

    // Verify feature flag is enabled
    const flagEnabled = await page.evaluate(() => {
      return (window as any).__featureFlags?.[FEATURE_FLAG_KEY];
    });
    expect(flagEnabled).toBe(true);

    // Verify editor is editable
    await page.click('[data-testid="editor-content"]');
    await page.keyboard.type('EU Beitrag');

    const content = await page.textContent('[data-testid="editor-content"]');
    expect(content).toContain('EU Beitrag');

    await browser.close();
  });

  test('WebSocket propagation: US edit should sync to EU reader', async () => {
    const browser = await chromium.launch();

    // US Editor context
    const usContext = await browser.newContext({ timezoneId: 'America/New_York' });
    const usPage = await usContext.newPage();

    // EU Reader context  
    const euContext = await browser.newContext({ timezoneId: 'Europe/Berlin' });
    const euPage = await euContext.newPage();

    const usWsEndpoint = await loginAndGetWebSocket(usPage, 'us-editor');
    const usWs = new WebSocket(usWsEndpoint);
    const usMessages: EditorMessage[] = [];
    usWs.on('message', (data) => usMessages.push(JSON.parse(data.toString())));

    await Promise.all([
      usPage.goto('/app/editor/post-123'),
      euPage.goto('/app/editor/post-123')  
    ]);

    await usPage.click('[data-testid="editor-content"]');
    await usPage.keyboard.type('Synced from US');

    // Verify EU reader received sync message
    await euPage.waitForFunction(() => {
      return (window as any).__editorState?.content?.includes('Synced from US');
    }, { timeout: 5000 });

    const euContent = await euPage.textContent('[data-testid="editor-content"]');
    expect(euContent).toContain('Synced from US');

    await usWs.close();
    await browser.close();
  });

  test('reconnection: should achieve eventual consistency after network drop', async () => {
    const browser = await chromium.launch();
    const context = await browser.newContext();
    const page = await context.newPage();

    await page.goto('/app/editor/post-123');
    const wsEndpoint = await getActiveWebSocket(page);
    const ws = new WebSocket(wsEndpoint);

    await page.click('[data-testid="editor-content"]');
    await page.keyboard.type('Before disconnect');

    // Simulate network drop
    await context.setOffline(true);
    ws.close();

    await page.click('[data-testid="editor-content"]');
    await page.keyboard.type('During disconnect');

    // Verify local queue has pending changes
    const localQueue = await page.evaluate(() => {
      return (window as any).__pendingChanges || [];
    });
    expect(localQueue.length).toBeGreaterThan(0);

    // Simulate reconnection
    await context.setOffline(false);

    // Wait for reconnection with exponential backoff
    await page.waitForFunction(() => {
      return (window as any).__wsConnected;
    }, { timeout: 10000 });

    // Verify queued changes synced after reconnect
    await page.waitForFunction(() => {
      const state = (window as any).__editorState;
      return state?.content?.includes('During disconnect') && state?.synced;
    }, { timeout: 10000 });

    // Verify server acknowledged all changes in order
    const finalContent = await page.textContent('[data-testid="editor-content"]');
    expect(finalContent).toContain('Before disconnect');
    expect(finalContent).toContain('During disconnect');

    await ws.close();
    await browser.close();
  });

  test('rollback: should gracefully degrade when flag is disabled', async () => {
    const browser = await chromium.launch();
    const context = await browser.newContext();
    const page = await context.newPage();

    // Enable flag initially
    await ldClient.toggleFlag(true, ['rollback-user']);

    await page.goto('/app/editor/post-123', {
      headers: { 'X-User-Key': 'rollback-user' }
    });

    // Verify editing is enabled
    await page.waitForSelector('[data-testid="editor-content"]');
    await page.click('[data-testid="editor-content"]');
    await page.keyboard.type('Pre-rollback content');

    // Disable feature flag
    await ldClient.toggleFlag(false, ['rollback-user']);

    // Wait for flag change to propagate
    await page.waitForTimeout(2000);
    await page.reload();

    // Verify graceful degradation - read-only mode
    const isReadOnly = await page.evaluate(() => {
      return (window as any).__editorState?.readOnly;
    });
    expect(isReadOnly).toBe(true);

    // Verify pending local changes handled correctly
    const pendingAlert = await page.evaluate(() => {
      return (window as any).__pendingChangesAlert;
    });
    expect(pendingAlert).toBeDefined();

    // Verify fallback UI shown
    const fallbackMessage = await page.textContent('[data-testid="fallback-message"]');
    expect(fallbackMessage).toContain('edit mode is currently unavailable');

    await browser.close();
  });

  async function loginAndGetWebSocket(page, userKey: string) {
    await page.goto('/login');
    await page.fill('[data-testid="username"]', userKey);
    await page.fill('[data-testid="password"]', 'password');
    await page.click('[data-testid="login-btn"]');

    const wsUrl = await page.evaluate(() => {
      return (window as any).__wsEndpoint;
    });
    return wsUrl;
  }

  async function getActiveWebSocket(page) {
    return await page.evaluate(() => {
      return (window as any).__wsEndpoint;
    });
  }
});
```

**Key Tooling & Steps:**
1. **Playwright** - Browser automation with `context.setOffline(true)` for network simulation
2. **LaunchDarkly SDK** - Programmatic flag toggling via `ldClient.toggleFlag()`
3. **`page.on('websocket')`** - Monitor WebSocket connection events
4. **`ws.on('message')`** - Capture and validate message frames
5. **Optimistic UI validation** - Assert local state via `page.evaluate()` before server ACK
6. **Reconnection testing** - Use `context.setOffline(true/false)` with polling for sync

