// Playwright test setup with two isolated contexts
const { test, expect } = require('@playwright/test');

test.describe('Collaborative Document Editor', () => {
  let docId;

  test.beforeEach(async ({ request }) => {
    docId = `test-doc-${Date.now()}-${Math.random().toString(36).slice(2)}`;
  });

  test('real-time presence and autosave sync between two users', async ({ browser }) => {
    const userA = await browser.newContext();
    const userB = await browser.newContext();

    const pageA = await userA.newPage();
    const pageB = await userB.newPage();

    await pageA.goto(`/doc/${docId}`);
    await pageB.goto(`/doc/${docId}`);

    // Verify presence indicators show both users
    await expect(pageA.locator('.presence')).toContainText('User B');
    await expect(pageB.locator('.presence')).toContainText('User A');

    // User A types; User B should see it within 1-2 seconds
    await pageA.locator('.editor').fill('Hello from User A');
    await expect(pageB.locator('.editor')).toHaveValue('Hello from User A', { timeout: 3000 });

    // Verify autosave to data store (mocked interval: 2s)
    await pageA.waitForTimeout(2500);
    const storedDoc = await request.get(`/api/docs/${docId}`);
    expect((await storedDoc.json()).content).toBe('Hello from User A');
  });

  test('offline reconnection and conflict resolution', async ({ browser }) => {
    const userA = await browser.newContext();
    const userB = await browser.newContext();

    const pageA = await userA.newPage();
    const pageB = await userB.newPage();

    await pageA.goto(`/doc/${docId}`);
    await pageB.goto(`/doc/${docId}`);

    // Simulate offline for User B
    await pageB.context().setOffline(true);
    await pageA.locator('.editor').fill('User A edit');
    await pageB.waitForTimeout(1000);

    // Reconnect User B
    await pageB.context().setOffline(false);
    await expect(pageB.locator('.editor')).toHaveValue('User A edit', { timeout: 5000 });

    // Concurrent edits - last-write-wins conflict resolution
    await pageB.locator('.editor').fill('User B edit');
    await pageA.locator('.editor').fill('User A edit');
    await pageB.waitForTimeout(2500); // Wait for autosave

    const finalDoc = await request.get(`/api/docs/${docId}`);
    expect((await finalDoc.json()).content).toMatch(/User (A|B) edit/);
  });
});
```

