- **Fault simulation**: Testing resilience under network partitions, regional outages, and broker unavailability

## Code Example

```javascript
import { test, expect } from '@playwright/test';
import Kafka from 'kafkajs';

const kafka = new Kafka({ clientId: 'e2e-test', brokers: ['localhost:9092'] });
const producer = kafka.producer();
const testTenantId = 'test-tenant-' + Date.now();

test.describe('Analytics Pipeline E2E', () => {
  test.beforeAll(async () => {
    await producer.connect();
  });

  test.afterAll(async () => {
    await producer.disconnect();
  });

  test('handles late and out-of-order events with idempotency', async () => {
    const baseTime = Date.now();
    const events = [
      { userId: 'user-1', action: 'page_view', timestamp: baseTime, tenantId: testTenantId },
      { userId: 'user-2', action: 'click', timestamp: baseTime + 1000, tenantId: testTenantId },
      { userId: 'user-1', action: 'page_view', timestamp: baseTime + 2000, tenantId: testTenantId },
    ];

    await producer.send({ topic: 'user-activity', messages: events.map(e => ({ value: JSON.stringify(e) })) });

    const lateEvents = [
      { userId: 'user-1', action: 'page_view', timestamp: baseTime - 3600000, tenantId: testTenantId },
    ];
    await producer.send({ topic: 'user-activity', messages: lateEvents.map(e => ({ value: JSON.stringify(e) })) });

    await waitForSnowflakeSync(15000);

    const row = await snowflake.query(`SELECT COUNT(*) as cnt FROM analytics.events WHERE tenant_id = '${testTenantId}'`);
    expect(row.cnt).toBe(4);

    await producer.send({ topic: 'user-activity', messages: events.map(e => ({ value: JSON.stringify(e) })) });
    await waitForSnowflakeSync(15000);

    const dupRow = await snowflake.query(`SELECT COUNT(*) as cnt FROM analytics.events WHERE tenant_id = '${testTenantId}'`);
    expect(dupRow.cnt).toBe(4);
  });

  test('handles regional outage and recovery', async () => {
    await simulateNetworkPartition();

    const eventsDuringOutage = generateEvents(testTenantId, 100);
    await expect(producer.send({ topic: 'user-activity', messages: eventsDuringOutage })).rejects.toThrow();

    await simulateNetworkRecovery();

    await producer.send({ topic: 'user-activity', messages: eventsDuringOutage });
    await waitForSnowflakeSync(20000);

    const row = await snowflake.query(`SELECT COUNT(*) as cnt FROM analytics.events WHERE tenant_id = '${testTenantId}'`);
    expect(row.cnt).toBe(100);
  });
});

function waitForSnowflakeSync(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

async function simulateNetworkPartition() {
  await producer.disconnect();
}

async function simulateNetworkRecovery() {
  await producer.connect();
}
```

