## Code Example

```javascript
const { test, expect } = require('@playwright/test');

test.describe('Note-taking PWA E2E', () => {
  let contextA, contextB, pageA, pageB;

  test.beforeEach(async ({ browser }) => {
    // Create two isolated browser contexts to simulate two devices
    contextA = await browser.newContext();
    contextB = await browser.newContext();
    pageA = await contextA.newPage();
    pageB = await contextB.newPage();

    // Seed initial notes into IndexedDB for both contexts
    await seedInitialNotes(pageA);
    await seedInitialNotes(pageB);
  });

  test('syncs notes without duplicates after going offline/online', async () => {
    // Step 1: Simulate offline mode on Device A
    await pageA.route('**/*', route => route.abort('offline'));

    // Step 2: Create and edit a note while offline
    const noteId = await createNoteOffline(pageA, 'Original Title', 'Original Content');
    await editNoteOffline(pageA, noteId, 'Updated Title', 'Updated Content');

    // Step 3: Bring Device B online and make a conflicting edit
    await pageB.goto('/');
    await pageB.waitForSelector('[data-testid="note-list"]');
    await editNote(pageB, noteId, 'Conflicting Title', 'Conflicting Content');

    // Step 4: Restore connectivity on Device A to trigger sync
    await pageA.unrouteAll();

    // Step 5: Verify sync completes within 10 seconds
    await expect(pageA.locator('[data-testid="sync-status"]')).toHaveText('Synced', { timeout: 10000 });

    // Step 6: Assert no duplicates and correct timestamps
    const notes = await getAllNotes(pageA);
    const duplicateNotes = notes.filter(n => n.title === 'Updated Title');

    expect(duplicateNotes).toHaveLength(1);
    expect(notes[0].updatedAt).toBeGreaterThan(notes[0].createdAt);
  });

  async function seedInitialNotes(page) {
    await page.evaluate(() => {
      const request = indexedDB.open('NotesDB', 1);
      request.onupgradeneeded = (event) => {
        const db = event.target.result;
        if (!db.objectStoreNames.contains('notes')) {
          db.createObjectStore('notes', { keyPath: 'id' });
        }
      };
      request.onsuccess = (event) => {
        const db = event.target.result;
        const tx = db.transaction('notes', 'readwrite');
        const store = tx.objectStore('notes');
        store.put({ id: 'note-1', title: 'Welcome', content: 'Welcome to the app!', createdAt: Date.now(), updatedAt: Date.now() });
      };
    });
  }

  async function createNoteOffline(page, title, content) {
    return await page.evaluate(([t, c]) => {
      return new Promise((resolve) => {
        const request = indexedDB.open('NotesDB', 1);
        request.onsuccess = (event) => {
          const db = event.target.result;
          const tx = db.transaction('notes', 'readwrite');
          const store = tx.objectStore('notes');
          const id = 'note-' + Date.now();
          store.put({ id, title: t, content: c, createdAt: Date.now(), updatedAt: Date.now() });
          tx.oncomplete = () => resolve(id);
        };
      });
    }, [title, content]);
  }

  async function editNote(page, id, title, content) {
    await page.click(`[data-testid="note-${id}"]`);
    await page.fill('[data-testid="title-input"]', title);
    await page.fill('[data-testid="content-input"]', content);
    await page.click('[data-testid="save-button"]');
  }

  async function getAllNotes(page) {
    return await page.evaluate(() => {
      return new Promise((resolve) => {
        const request = indexedDB.open('NotesDB', 1);
        request.onsuccess = (event) => {
          const db = event.target.result;
          const tx = db.transaction('notes', 'readonly');
          const store = tx.objectStore('notes');
          const getAll = store.getAll();
          getAll.onsuccess = () => resolve(getAll.result);
        };
      });
    });
  }
});
```

