import { test, expect } from '@playwright/test';

const REGIONS = ['NA', 'EU', 'APAC'];

test.describe('Financial Reporting Portal E2E', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto('/auth/login');
  });

  test('should reconcile data across regions with eventual consistency', async ({ page }) => {
    // Seed identical transactions across all regions
    await seedIdenticalTransactions(REGIONS);

    // Inject regional latency to simulate eventual consistency
    await mockService.delay('NA', 5000);
    await mockService.delay('EU', 3000);
    await mockService.delay('APAC', 8000);

    // Navigate to dashboard and verify data reconciliation
    await page.click('[data-testid="refresh-data"]');
    await expect(page.locator('[data-testid="total-revenue"]')).toHaveText('$300,000');
  });

  test('should hide PII for non-admin users via feature flag', async ({ page }) => {
    // Set feature flag to hide PII
    await featureFlag.set('show-pii', false);

    await page.loginAs('non-admin');
    await page.goto('/reports');

    // Verify PII is masked
    await expect(page.locator('[data-testid="customer-ssn"]')).toHaveText('***-**-1234');

    // Verify rollback behavior when flag changes
    await featureFlag.set('show-pii', true);
    await page.reload();
    await expect(page.locator('[data-testid="customer-ssn"]')).toHaveText('123-45-6789');
  });

  test('should handle regional outage gracefully', async ({ page }) => {
    // Simulate EU region outage
    await mockService.fail('EU', 503);

    await page.goto('/reports');
    await expect(page.locator('[data-testid="eu-status"]')).toContainText('Region unavailable');

    // Verify other regions still function
    await expect(page.locator('[data-testid="na-revenue"]')).toBeVisible();

    // Restore EU and verify reconciliation
    await mockService.restore('EU');
    await page.click('[data-testid="reconcile"]');
    await expect(page.locator('[data-testid="eu-status"]')).toContainText('Synced');
  });

  test('should enforce role-based access control', async ({ page }) => {
    await page.loginAs('admin');
    await page.goto('/reports');
    await expect(page.locator('[data-testid="admin-panel"]')).toBeVisible();

    await page.loginAs('viewer');
    await page.goto('/reports');
    await expect(page.locator('[data-testid="admin-panel"]')).not.toBeVisible();
  });
});
