questions.answer:
Use Playwright to create two isolated browser contexts (A and B) connected to the same shared document via WebSocket.

**Setup:**
1. Seed a test document via API with known initial content
2. Launch both browser contexts pointing to the collaborative editor
3. Initialize WebSocket message interception on both pages

**Test Steps:**
```javascript
import { test, expect, chromium } from '@playwright/test';

test.describe('Collaborative Document Editor E2E', () => {
  let documentId: string;

  test.beforeAll(async ({ request }) => {
    const response = await request.post('/api/documents', {
      data: { title: 'Test Doc', content: 'Initial content\n' }
    });
    documentId = (await response.json()).id;
  });

  test('real-time sync with offline reconciliation', async ({ browser }) => {
    const ctxA = await browser.newContext();
    const ctxB = await browser.newContext();
    const pageA = await ctxA.newPage();
    const pageB = await ctxB.newPage();

    // Track WebSocket messages
    const messagesA: string[] = [];
    const messagesB: string[] = [];

    await pageA.route('**/ws/**', route => {
      route.fulfill({ status: 200, body: '' });
      pageA.on('websocket', ws => {
        ws.on('framesent', data => messagesA.push(data.payload));
        ws.on('framereceived', data => messagesA.push(data.payload));
      });
    });

    // Navigate both users to same document
    await Promise.all([
      pageA.goto(`/editor/${documentId}`),
      pageB.goto(`/editor/${documentId}`)
    ]);
    await expect(pageA.locator('.editor')).toHaveText('Initial content\n');

    // Step 1: User A makes an edit
    await pageA.locator('.editor').click();
    await pageA.keyboard.type(' User A edit');

    // Step 2: Verify User B receives the change via WebSocket
    await expect(pageB.locator('.editor')).toHaveText('Initial content\n User A edit', { timeout: 5000 });

    // Step 3: Take User A offline
    await ctxA.setOffline(true);

    // Step 4: Make offline edits on User A and online edits on User B
    await pageA.locator('.editor').click();
    await pageA.keyboard.type(' (offline edit)'); // This queues locally
    await pageB.locator('.editor').click();
    await pageB.keyboard.type(' User B online edit');

    // Verify User A still shows offline state
    const offlineIndicator = pageA.locator('.connection-status');
    await expect(offlineIndicator).toHaveText('Offline');

    // Step 5: Reconnect User A
    await ctxA.setOffline(false);

    // Step 6: Verify reconciliation with conflict-resolution policy
    // Assuming CRDT merge policy: both edits should be present
    await expect(pageA.locator('.editor')).toHaveText(
      /offline edit/,
      { timeout: 5000 }
    );

    // Step 7: Eventual consistency check - both users see identical content
    await expect.poll(async () => {
      const contentA = await pageA.locator('.editor').textContent();
      const contentB = await pageB.locator('.editor').textContent();
      return contentA === contentB ? contentA : null;
    }, {
      timeout: 30000,
      message: 'Both users should see the same final content within 30s'
    }).then(async (content) => {
      expect(content).toMatch(/User A edit/);
      expect(content).toMatch(/User B online edit/);
      expect(content).toMatch(/offline edit/);
    });

    // Verify WebSocket message sequence for debugging
    console.log('Messages on A:', messagesA.length);
    console.log('Messages on B:', messagesB.length);

    await ctxA.close();
    await ctxB.close();
  });

  test('last-writer-wins conflict resolution', async ({ browser }) => {
    // Similar setup with explicit conflict assertion
    const ctx = await browser.newContext();
    await ctx.setOffline(true);
    const page = await ctx.newPage();
    await page.goto(`/editor/${documentId}`);

    await page.locator('.editor').fill('Version A');
    await ctx.setOffline(false);

    // Poll until content matches expected LWW result
    await expect.poll(async () => {
      const text = await page.locator('.editor').textContent();
      return text?.includes('Version') ? text : null;
    }, { timeout: 30000 });

    await ctx.close();
  });
});
```

**Latency Simulation:**
```javascript
await page.context().route('**/ws/**', route => {
  route.continue({ delay: 500 }); // Add 500ms latency
});
```

