```javascript
// k6 load test with fault injection
import http from 'k6/http';
import { check, sleep } from 'k6';

export const options = {
  vus: 1000,
  duration: '30s',
  thresholds: {
    http_req_duration: ['p(95)<500'],
  },
};

const tenants = ['tenant-a', 'tenant-b', 'tenant-c'];
const coupons = { 'tenant-a': 'DISC10', 'tenant-b': 'SAVE20', 'tenant-c': 'FREESHIP' };

export default function () {
  const tenant = tenants[Math.floor(Math.random() * tenants.length)];
  const coupon = coupons[tenant];

  // Apply coupon to cart
  const cartRes = http.post('https://gateway/api/cart', 
    JSON.stringify({ tenant, productId: 'prod-123', coupon }),
    { headers: { 'Content-Type': 'application/json' } }
  );

  check(cartRes, {
    'tenant isolation': (r) => r.json('tenant') === tenant,
    'discount applied': (r) => r.json('discount') > 0,
    'status is 200': (r) => r.status === 200,
  });

  // Place order
  const orderRes = http.post('https://gateway/api/orders',
    JSON.stringify({ tenant, cartId: cartRes.json('cartId') }),
    { headers: { 'Content-Type': 'application/json' } }
  );

  check(orderRes, {
    'order created': (r) => r.status === 201,
    'order integrity': (r) => r.json('orderId') !== undefined,
  });

  sleep(1);
}

// Fault injection via Kubernetes API:
// 1. Redis cache miss: kubectl exec redis-0 -- redis-cli FLUSHDB
// 2. DB failover: kubectl delete pod postgres-primary-0
```

