## Key Concepts
- End-to-end test orchestration across ingestion, broker, cache, storage, and UI
- Per-tenant data isolation and security boundaries
- Real-time WebSocket delivery and latency budgets
- Fault injection and resilience under peak load
- Telemetry, tracing, and reproducibility

## Code Example

```javascript
// Seed data and tenant configuration
const tenants = [
  { id: 'tenant-a', name: 'Acme Corp', apiKey: 'key_a_xxx' },
  { id: 'tenant-b', name: 'Beta Inc', apiKey: 'key_b_xxx' },
  { id: 'tenant-c', name: 'Gamma LLC', apiKey: 'key_c_xxx' },
  { id: 'tenant-d', name: 'Delta Co', apiKey: 'key_d_xxx' },
  { id: 'tenant-e', name: 'Epsilon Ltd', apiKey: 'key_e_xxx' },
];

// Traffic pattern: 20k events/second per tenant
const EVENTS_PER_SECOND = 20000;
const DURATION_SECONDS = 60;

async function ingestEvents(tenant, emitFn) {
  const interval = 1000 / EVENTS_PER_SECOND;
  for (let i = 0; i < DURATION_SECONDS * EVENTS_PER_SECOND; i++) {
    emitFn({
      tenantId: tenant.id,
      eventId: uuid(),
      timestamp: Date.now(),
      payload: { value: Math.random(), tag: tenant.id },
    });
    await sleep(interval);
  }
}

// Fault injection: broker drop
async function injectBrokerDrop(broker, dropPercent = 5) {
  const originalPublish = broker.publish.bind(broker);
  broker.publish = async (topic, msg) => {
    if (Math.random() * 100 < dropPercent) return; // drop
    return originalPublish(topic, msg);
  };
}

// Fault injection: cache eviction
function evictCacheKey(cache, keyPattern) {
  const keys = cache.keys().filter(k => keyPattern.test(k));
  keys.forEach(k => cache.delete(k));
}

// Verification: detect cross-tenant leakage
async function verifyIsolation(dashboard, expectedTenantId) {
  const messages = await dashboard.getReceivedMessages();
  for (const msg of messages) {
    if (msg.tenantId !== expectedTenantId) {
      throw new Error(`CROSS-TENANT LEAK: ${msg.tenantId} seen on ${expectedTenantId}'s dashboard`);
    }
  }
}

// Latency verification
function verifyLatency(msgTimestamp, receiveTimestamp) {
  const latency = receiveTimestamp - msgTimestamp;
  if (latency > 2000) {
    throw new Error(`LATENCY BREACH: ${latency}ms exceeds 2s threshold`);
  }
  return latency;
}

// Main test orchestration
async function runE2ETest() {
  const broker = new MessageBroker();
  const cache = new TenantCache();
  const storage = new TenantStorage();
  const dashboards = {};

  // Setup WebSocket dashboards per tenant
  for (const tenant of tenants) {
    dashboards[tenant.id] = new WebSocketDashboard({
      authToken: tenant.apiKey,
      onMessage: (msg, ts) => {
        verifyIsolation(dashboards[tenant.id], tenant.id);
        verifyLatency(msg.timestamp, ts);
      },
    });
  }

  // Inject faults mid-test
  setTimeout(() => injectBrokerDrop(broker, 5), 30000);
  setTimeout(() => evictCacheKey(cache, /^tenant-a/), 45000);

  // Run traffic for all tenants in parallel
  await Promise.all(
    tenants.map(tenant => ingestEvents(tenant, msg => broker.publish(`${tenant.id}/events`, msg)))
  );

  // Final assertions
  console.log('All events processed. Verifying final state...');
  for (const tenant of tenants) {
    const storageData = await storage.getAll(tenant.id);
    assert.strictEqual(storageData.length, EVENTS_PER_SECOND * DURATION_SECONDS);
    console.log(`✓ ${tenant.name}: ${storageData.length} events stored`);
  }
}
```

## What to Look For in a Strong Answer
1. Clear test structure covering setup, execution, and assertions
2. Proper isolation verification at each layer (cache, broker, storage)
3. Realistic fault injection with measurable impact
4. Latency assertions tied to actual message timestamps
5. Reproducibility through seed data and deterministic traffic

